"""Ease of Movement — 价格移动效率指标"""
from typing import Dict, List, Optional
from dataclasses import dataclass
from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class EaseOfMovementConfig:
    period: int = 14
    volume_divisor: float = 10000.0


class EaseOfMovement(Strategy):
    def __init__(self, exchange=None, config: Optional[EaseOfMovementConfig] = None):
        self.exchange = exchange
        self.config = config or EaseOfMovementConfig()

    @property
    def name(self) -> str:
        return "easeofmovement"

    def generate_signal(self, coin: str, klines: List[Dict] = None) -> TradingSignal:
        p = self.config.period
        if not klines or len(klines) < p + 2:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"] if klines else 0)

        emv_raw = []
        for i in range(1, len(klines)):
            mid_move = (klines[i]["high"] + klines[i]["low"]) / 2 - \
                       (klines[i - 1]["high"] + klines[i - 1]["low"]) / 2
            box_ratio = klines[i]["high"] - klines[i]["low"]
            if box_ratio == 0 or klines[i]["volume"] == 0:
                emv_raw.append(0.0)
            else:
                emv_raw.append(mid_move / (klines[i]["volume"] / self.config.volume_divisor / box_ratio))

        emv = sum(emv_raw[-p:]) / p
        prev_emv = sum(emv_raw[-(p + 1):-1]) / p

        if emv > 0 and prev_emv <= 0:
            signal = Signal.BUY
        elif emv < 0 and prev_emv >= 0:
            signal = Signal.SELL
        else:
            signal = Signal.HOLD

        return TradingSignal(signal=signal, confidence=0.6,
                             coin=coin, timestamp=klines[-1]["time"],
                             metadata={"emv": emv, "prev_emv": prev_emv})

"""Ehlers Instantaneous Trendline — Hilbert变换趋势线"""
import math
from typing import Dict, List, Optional
from dataclasses import dataclass
from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class EhlersITLConfig:
    alpha: float = 0.07


class EhlersITL(Strategy):
    def __init__(self, exchange=None, config: Optional[EhlersITLConfig] = None):
        self.exchange = exchange
        self.config = config or EhlersITLConfig()

    @property
    def name(self) -> str:
        return "ehlersitl"

    def generate_signal(self, coin: str, klines: List[Dict] = None) -> TradingSignal:
        if not klines or len(klines) < 12:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"] if klines else 0)

        prices = [(c["high"] + c["low"]) / 2 for c in klines]
        itl = self._calc_itl(prices)

        if len(itl) < 5:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"])

        current = itl[-1]
        lag = itl[-3]
        prev_current = itl[-2]
        prev_lag = itl[-4]

        if current > lag and prev_current <= prev_lag:
            signal = Signal.BUY
        elif current < lag and prev_current >= prev_lag:
            signal = Signal.SELL
        else:
            signal = Signal.HOLD

        return TradingSignal(signal=signal, confidence=0.7,
                             coin=coin, timestamp=klines[-1]["time"],
                             metadata={"itl": current, "itl_lag": lag})

    def _calc_itl(self, prices):
        a = self.config.alpha
        n = len(prices)
        itl = [0.0] * n

        for i in range(n):
            if i < 7:
                itl[i] = prices[i]
            else:
                itl[i] = (a - a * a / 4) * prices[i] + \
                         0.5 * a * a * prices[i - 1] - \
                         (a - 0.75 * a * a) * prices[i - 2] + \
                         2 * (1 - a) * itl[i - 1] - \
                         (1 - a) ** 2 * itl[i - 2]
        return itl

"""EMA Cross Fast — 快速EMA交叉（短周期专用）"""
from typing import Dict, List, Optional
from dataclasses import dataclass
from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class EMACrossFastConfig:
    fast_period: int = 3
    slow_period: int = 8


class EMACrossFast(Strategy):
    def __init__(self, exchange=None, config: Optional[EMACrossFastConfig] = None):
        self.exchange = exchange
        self.config = config or EMACrossFastConfig()

    @property
    def name(self) -> str:
        return "emacrossfast"

    def _ema(self, prices, period):
        if len(prices) < period:
            return prices[-1] if prices else 0
        k = 2 / (period + 1)
        ema = sum(prices[:period]) / period
        for p in prices[period:]:
            ema = p * k + ema * (1 - k)
        return ema

    def generate_signal(self, coin: str, klines: List[Dict] = None) -> TradingSignal:
        need = self.config.slow_period + 2
        if not klines or len(klines) < need:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"] if klines else 0)

        closes = [c["close"] for c in klines]
        fast = self._ema(closes, self.config.fast_period)
        slow = self._ema(closes, self.config.slow_period)
        prev_fast = self._ema(closes[:-1], self.config.fast_period)
        prev_slow = self._ema(closes[:-1], self.config.slow_period)

        if fast > slow and prev_fast <= prev_slow:
            signal = Signal.BUY
        elif fast < slow and prev_fast >= prev_slow:
            signal = Signal.SELL
        else:
            signal = Signal.HOLD

        spread = (fast - slow) / slow * 100 if slow != 0 else 0
        return TradingSignal(signal=signal, confidence=min(abs(spread) / 0.5, 1.0),
                             coin=coin, timestamp=klines[-1]["time"],
                             metadata={"fast_ema": fast, "slow_ema": slow, "spread_pct": spread})

"""Fisher Transform — 价格正态化变换信号"""
from typing import Dict, List, Optional
from dataclasses import dataclass
import math
from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class FisherTransformConfig:
    period: int = 9


class FisherTransform(Strategy):
    def __init__(self, exchange=None, config: Optional[FisherTransformConfig] = None):
        self.exchange = exchange
        self.config = config or FisherTransformConfig()

    @property
    def name(self) -> str:
        return "fishertransform"

    def generate_signal(self, coin: str, klines: List[Dict] = None) -> TradingSignal:
        p = self.config.period
        if not klines or len(klines) < p + 2:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"] if klines else 0)

        fisher, prev_fisher = self._calc_fisher(klines, p)

        if fisher > 0 and prev_fisher <= 0:
            signal = Signal.BUY
        elif fisher < 0 and prev_fisher >= 0:
            signal = Signal.SELL
        else:
            signal = Signal.HOLD

        return TradingSignal(signal=signal, confidence=min(abs(fisher) / 2, 1.0),
                             coin=coin, timestamp=klines[-1]["time"],
                             metadata={"fisher": fisher, "prev_fisher": prev_fisher})

    def _calc_fisher(self, klines, period):
        def _ft(bars):
            highs = [c["high"] for c in bars[-period:]]
            lows = [c["low"] for c in bars[-period:]]
            highest = max(highs)
            lowest = min(lows)
            mid = (bars[-1]["high"] + bars[-1]["low"]) / 2
            if highest == lowest:
                x = 0.0
            else:
                x = 2 * (mid - lowest) / (highest - lowest) - 1
            x = max(-0.999, min(0.999, x))
            return 0.5 * math.log((1 + x) / (1 - x))

        fisher = _ft(klines)
        prev_fisher = _ft(klines[:-1])
        return fisher, prev_fisher

"""Fair Value Gap (FVG) — 公允价值缺口策略

3根K线模式：
- 看涨FVG：第3根最低价 > 第1根最高价（向上跳空），价格回踩缺口做多
- 看跌FVG：第3根最高价 < 第1根最低价（向下跳空），价格反弹缺口做空

交易逻辑：
- 检测到FVG后，等价格回到缺口区域（50%回填位）时入场
- 天生多空双向，signal close正常触发
"""
from typing import Dict, List, Optional
from dataclasses import dataclass

from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class FVGConfig:
    lookback: int = 20          # 回看多少根K线寻找FVG
    min_gap_pct: float = 0.001  # 最小缺口百分比（过滤噪音，0.1%）


class FVG(Strategy):
    def __init__(self, exchange=None, config: Optional[FVGConfig] = None):
        self.exchange = exchange
        self.config = config or FVGConfig()

    @property
    def name(self) -> str:
        return "fvg"

    def generate_signal(self, coin: str, klines: List[Dict] = None) -> TradingSignal:
        min_required = self.config.lookback + 3
        if not klines or len(klines) < min_required:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"] if klines else 0,
                                 metadata={"reason": "Insufficient klines"})

        current_price = klines[-1]["close"]

        # 在回看窗口内寻找最近的未填补FVG
        best_bull_fvg = None  # (gap_low, gap_high, gap_mid, age)
        best_bear_fvg = None

        search_start = max(0, len(klines) - self.config.lookback - 2)
        for i in range(search_start, len(klines) - 2):
            c1 = klines[i]
            c3 = klines[i + 2]

            # 看涨FVG：第3根最低 > 第1根最高（向上跳空）
            if c3["low"] > c1["high"]:
                gap_low = c1["high"]
                gap_high = c3["low"]
                gap_size = (gap_high - gap_low) / gap_low if gap_low > 0 else 0
                if gap_size >= self.config.min_gap_pct:
                    # 检查缺口是否已被后续K线填补
                    filled = False
                    for j in range(i + 3, len(klines)):
                        if klines[j]["low"] <= gap_low:
                            filled = True
                            break
                    if not filled:
                        age = len(klines) - 1 - i
                        gap_mid = (gap_low + gap_high) / 2
                        if best_bull_fvg is None or age < best_bull_fvg[3]:
                            best_bull_fvg = (gap_low, gap_high, gap_mid, age)

            # 看跌FVG：第3根最高 < 第1根最低（向下跳空）
            if c3["high"] < c1["low"]:
                gap_high = c1["low"]
                gap_low = c3["high"]
                gap_size = (gap_high - gap_low) / gap_low if gap_low > 0 else 0
                if gap_size >= self.config.min_gap_pct:
                    filled = False
                    for j in range(i + 3, len(klines)):
                        if klines[j]["high"] >= gap_high:
                            filled = True
                            break
                    if not filled:
                        age = len(klines) - 1 - i
                        gap_mid = (gap_low + gap_high) / 2
                        if best_bear_fvg is None or age < best_bear_fvg[3]:
                            best_bear_fvg = (gap_low, gap_high, gap_mid, age)

        # 判断信号：价格进入未填补的FVG区域
        signal = Signal.HOLD
        confidence = 0.0
        metadata = {}

        if best_bull_fvg:
            gap_low, gap_high, gap_mid, age = best_bull_fvg
            # 价格回踩到缺口区域 → 做多
            if gap_low <= current_price <= gap_high:
                signal = Signal.BUY
                confidence = 1.0 - (current_price - gap_low) / (gap_high - gap_low) if gap_high > gap_low else 0.5
                metadata = {"fvg_type": "bullish", "gap_low": gap_low,
                           "gap_high": gap_high, "age": age}

        if best_bear_fvg:
            gap_low, gap_high, gap_mid, age = best_bear_fvg
            # 价格反弹到缺口区域 → 做空
            if gap_low <= current_price <= gap_high:
                # 如果同时有牛熊FVG，取更近的那个
                if signal == Signal.BUY:
                    if age < best_bull_fvg[3]:
                        signal = Signal.SELL
                        confidence = (current_price - gap_low) / (gap_high - gap_low) if gap_high > gap_low else 0.5
                        metadata = {"fvg_type": "bearish", "gap_low": gap_low,
                                   "gap_high": gap_high, "age": age}
                else:
                    signal = Signal.SELL
                    confidence = (current_price - gap_low) / (gap_high - gap_low) if gap_high > gap_low else 0.5
                    metadata = {"fvg_type": "bearish", "gap_low": gap_low,
                               "gap_high": gap_high, "age": age}

        return TradingSignal(signal=signal, confidence=confidence,
                             coin=coin, timestamp=klines[-1]["time"],
                             metadata=metadata)

"""Grid Trading — 网格交易（震荡市跌一格买入，回弹平仓）"""
from typing import Dict, List, Optional
from dataclasses import dataclass
from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class GridConfig:
    grid_pct: float = 1.5
    lookback: int = 20


class Grid(Strategy):
    def __init__(self, exchange=None, config: Optional[GridConfig] = None):
        self.exchange = exchange
        self.config = config or GridConfig()

    @property
    def name(self) -> str:
        return "grid"

    def generate_signal(self, coin: str, klines: List[Dict] = None) -> TradingSignal:
        lb = self.config.lookback
        if not klines or len(klines) < lb + 1:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"] if klines else 0)

        closes = [c["close"] for c in klines]
        close = closes[-1]
        prev_close = closes[-2]

        ref_price = max(closes[-lb:])
        drop_pct = (ref_price - close) / ref_price * 100 if ref_price != 0 else 0

        prev_ref = max(closes[-(lb + 1):-1])
        prev_drop = (prev_ref - prev_close) / prev_ref * 100 if prev_ref != 0 else 0

        if drop_pct >= self.config.grid_pct and prev_drop < self.config.grid_pct:
            signal = Signal.BUY
        elif drop_pct < self.config.grid_pct * 0.3 and prev_drop >= self.config.grid_pct * 0.3:
            signal = Signal.SELL
        else:
            signal = Signal.HOLD

        return TradingSignal(signal=signal, confidence=min(drop_pct / (self.config.grid_pct * 2), 1.0),
                             coin=coin, timestamp=klines[-1]["time"],
                             metadata={"drop_pct": drop_pct, "ref_price": ref_price,
                                        "grid_pct": self.config.grid_pct})

"""HMA — Hull Moving Average 趋势方向"""
from typing import Dict, List, Optional
from dataclasses import dataclass
import math
from core.strategy import Strategy, Signal, TradingSignal


@dataclass
class HMAConfig:
    period: int = 9


class HMA(Strategy):
    def __init__(self, exchange=None, config: Optional[HMAConfig] = None):
        self.exchange = exchange
        self.config = config or HMAConfig()

    @property
    def name(self) -> str:
        return "hma"

    def _wma(self, prices, period):
        if len(prices) < period:
            return prices[-1] if prices else 0
        window = prices[-period:]
        weight_sum = period * (period + 1) / 2
        return sum(window[i] * (i + 1) for i in range(period)) / weight_sum

    def _hma(self, prices, period):
        half_p = max(int(period / 2), 1)
        sqrt_p = max(int(math.sqrt(period)), 1)
        if len(prices) < period + sqrt_p:
            return None, None

        diff_series = []
        for i in range(sqrt_p + 1):
            end = len(prices) - sqrt_p + i
            sub = prices[:end]
            wma_half = self._wma(sub, half_p)
            wma_full = self._wma(sub, period)
            diff_series.append(2 * wma_half - wma_full)

        hma = self._wma(diff_series, sqrt_p)
        prev_hma = self._wma(diff_series[:-1], sqrt_p) if len(diff_series) > sqrt_p else None
        return hma, prev_hma

    def generate_signal(self, coin: str, klines: List[Dict] = None) -> TradingSignal:
        p = self.config.period
        need = p + int(math.sqrt(p)) + 2
        if not klines or len(klines) < need:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"] if klines else 0)

        closes = [c["close"] for c in klines]
        hma, prev_hma = self._hma(closes, p)

        if hma is None or prev_hma is None:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                                 timestamp=klines[-1]["time"])

        if hma > prev_hma and closes[-1] > hma:
            signal = Signal.BUY
        elif hma < prev_hma and closes[-1] < hma:
            signal = Signal.SELL
        else:
            signal = Signal.HOLD

        return TradingSignal(signal=signal, confidence=0.7,
                             coin=coin, timestamp=klines[-1]["time"],
                             metadata={"hma": hma, "prev_hma": prev_hma})
